messages.content:
{
  "children": [
    {
      "name": "IngestData",
      "purpose": "Read data from external source and store in raw_data",
      "behavior": "Reads input source, parses data, writes to raw_data store, logs ingestion",
      "boundary": {
        "in_scope": [
          "reading source",
          "parsing",
          "writing to raw_data",
          "logging"
        ],
        "out_of_scope": [
          "transformation",
          "validation",
          "export"
        ]
      },
      "semantic_inputs": [
        "input: Any - JSON with action and source"
      ],
      "semantic_outputs": [
        "ingestion_result: Any - JSON with success, records_ingested, errors"
      ],
      "preconditions": [
        "input contains valid source"
      ],
      "postconditions": [
        "raw_data contains ingested records"
      ],
      "guarantees": [
        "logs ingestion details"
      ],
      "composition_role": "transform",
      "stop_decompose": false,
      "stop_reason": "",
      "inputs": [
        {
          "name": "input",
          "type": "dict",
          "description": "JSON with action and source",
          "source": "parent input"
        }
      ],
      "outputs": [
        {
          "name": "ingestion_result",
          "type": "dict",
          "description": "JSON with success, records_ingested, errors",
          "consumer": "parent"
        }
      ],
      "signature": "def IngestData(input: dict) -> dict"
    },
    {
      "name": "TransformData",
      "purpose": "Apply transformations to raw data and store in processed_data",
      "behavior": "Reads raw_data, applies transformation rules, writes to processed_data, logs transformation",
      "boundary": {
        "in_scope": [
          "reading raw_data",
          "transforming",
          "writing to processed_data",
          "logging"
        ],
        "out_of_scope": [
          "ingestion",
          "validation",
          "export"
        ]
      },
      "semantic_inputs": [
        "transform_config: Any - Transformation rules from parent"
      ],
      "semantic_outputs": [
        "transformation_result: Any - JSON with success, records_transformed, errors"
      ],
      "preconditions": [
        "raw_data is populated"
      ],
      "postconditions": [
        "processed_data contains transformed records"
      ],
      "guarantees": [
        "logs transformation details"
      ],
      "composition_role": "transform",
      "stop_decompose": false,
      "stop_reason": "",
      "inputs": [
        {
          "name": "transform_config",
          "type": "dict",
          "description": "Transformation rules from parent",
          "source": "parent input"
        }
      ],
      "outputs": [
        {
          "name": "transformation_result",
          "type": "dict",
          "description": "JSON with success, records_transformed, errors",
          "consumer": "parent"
        }
      ],
      "signature": "def TransformData(transform_config: dict) -> dict"
    },
    {
      "name": "ValidateQuality",
      "purpose": "Check quality of processed data and mark invalid records",
      "behavior": "Reads processed_data, applies validation rules, marks invalid records, logs validation",
      "boundary": {
        "in_scope": [
          "reading processed_data",
          "validating",
          "marking invalid records",
          "logging"
        ],
        "out_of_scope": [
          "ingestion",
          "transformation",
          "export"
        ]
      },
      "semantic_inputs": [
        "validation_rules: Any - Quality criteria from parent"
      ],
      "semantic_outputs": [
        "validation_result: Any - JSON with success, valid_count, invalid_count, errors"
      ],
      "preconditions": [
        "processed_data is populated"
      ],
      "postconditions": [
        "processed_data has validity flags"
      ],
      "guarantees": [
        "logs validation details"
      ],
      "composition_role": "validate",
      "stop_decompose": false,
      "stop_reason": "",
      "inputs": [
        {
          "name": "validation_rules",
          "type": "dict",
          "description": "Quality criteria from parent",
          "source": "parent input"
        }
      ],
      "outputs": [
        {
          "name": "validation_result",
          "type": "dict",
          "description": "JSON with success, valid_count, invalid_count, errors",
          "consumer": "parent"
        }
      ],
      "signature": "def ValidateQuality(validation_rules: dict) -> dict"
    },
    {
      "name": "ExportResults",
      "purpose": "Export only valid records from processed_data to output",
      "behavior": "Reads processed_data, filters valid records, formats output, logs export",
      "boundary": {
        "in_scope": [
          "reading processed_data",
          "filtering valid records",
          "formatting output",
          "logging"
        ],
        "out_of_scope": [
          "ingestion",
          "transformation",
          "validation"
        ]
      },
      "semantic_inputs": [
        "export_format: Any - Output format specification"
      ],
      "semantic_outputs": [
        "export_result: Any - JSON with success, records_exported, errors, data"
      ],
      "preconditions": [
        "processed_data has validity flags"
      ],
      "postconditions": [
        "output contains only valid records"
      ],
      "guarantees": [
        "logs export details",
        "exports only valid records"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": "",
      "inputs": [
        {
          "name": "export_format",
          "type": "dict",
          "description": "Output format specification",
          "source": "parent input"
        }
      ],
      "outputs": [
        {
          "name": "export_result",
          "type": "dict",
          "description": "JSON with success, records_exported, errors, data",
          "consumer": "parent"
        }
      ],
      "signature": "def ExportResults(export_format: dict) -> dict"
    }
  ],
  "interface_preservation": {
    "parent_inputs_covered_by": {
      "input": "IngestData",
      "transform_config": "TransformData",
      "validation_rules": "ValidateQuality",
      "export_format": "ExportResults"
    },
    "parent_outputs_produced_by": {
      "ingestion_result": "IngestData",
      "transformation_result": "TransformData",
      "validation_result": "ValidateQuality",
      "export_result": "ExportResults"
    }
  },
  "dataflow_edges": [
    {
      "from_node": "parent",
      "from_output": "input",
      "to_node": "IngestData",
      "to_input": "input",
      "note": "parent passes input with action and source to IngestData"
    },
    {
      "from_node": "parent",
      "from_output": "input",
      "to_node": "TransformData",
      "to_input": "transform_config",
      "note": "parent passes transformation rules from input to TransformData"
    },
    {
      "from_node": "parent",
      "from_output": "input",
      "to_node": "ValidateQuality",
      "to_input": "validation_rules",
      "note": "parent passes validation rules from input to ValidateQuality"
    },
    {
      "from_node": "parent",
      "from_output": "input",
      "to_node": "ExportResults",
      "to_input": "export_format",
      "note": "parent passes export format from input to ExportResults"
    },
    {
      "from_node": "IngestData",
      "from_output": "ingestion_result",
      "to_node": "parent",
      "to_input": "output",
      "note": "IngestData returns ingestion_result to parent"
    },
    {
      "from_node": "TransformData",
      "from_output": "transformation_result",
      "to_node": "parent",
      "to_input": "output",
      "note": "TransformData returns transformation_result to parent"
    },
    {
      "from_node": "ValidateQuality",
      "from_output": "validation_result",
      "to_node": "parent",
      "to_input": "output",
      "note": "ValidateQuality returns validation_result to parent"
    },
    {
      "from_node": "ExportResults",
      "from_output": "export_result",
      "to_node": "parent",
      "to_input": "output",
      "note": "ExportResults returns export_result to parent"
    }
  ]
}
